 1	import { Button, Flex, FlexItem } from "@patternfly/react-core";
 2	import { MinusCircleIcon } from "@patternfly/react-icons";
 3	import * as React from "react";
 4	
 5	export const WithRemoveButton = ({
 6	  children,
 7	  isDisabled,
 8	  onClick,
 9	  direction = "row",
10	  grow = true,
11	  dataTest,
12	  ariaLabel,
13	}: {
14	  children?: React.ReactNode;
15	  isDisabled: boolean;
16	  grow?: boolean;
17	  direction?: "column" | "columnReverse" | "row" | "rowReverse";
18	  onClick: () => void;
19	  dataTest: string;
20	  ariaLabel?: string;
21	}) => {
22	  return (
23	    <Flex direction={{ default: direction }} flexWrap={{ default: "nowrap" }}>
24	      <FlexItem
25	        grow={grow ? { default: "grow" } : undefined}
26	        spacer={{ default: "spacerSm" }}
27	      >
28	        {children}
29	      </FlexItem>
30	
31	      <FlexItem id="remove-button">
32	        <Button
33	          type="button"
34	          variant="plain"
35	          onClick={onClick}
36	          isDisabled={isDisabled}
37	          data-test={dataTest}
38	          aria-label={ariaLabel}
39	        >
40	          <MinusCircleIcon />
41	        </Button>
42	      </FlexItem>
43	    </Flex>
44	  );
45	};

